// Normalize input from either Gmail Trigger or Webhook
const item = $input.item.json;

function asText(value) {
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  if (Array.isArray(value)) {
    return value.map((entry) => asText(entry)).filter(Boolean).join(', ');
  }
  if (value && typeof value === 'object') {
    return asText(value.text || value.value || value.email || value.address || value.name || value.html || '');
  }
  return '';
}

const looksLikeGmail = !!(item.threadId || item.historyId || item.internalDate || item.snippet || item.labelIds);
const webhookBody = item.body && typeof item.body === 'object' ? item.body : item;

let triggerType = 'unknown';
let source = 'unknown';
let subject = '';
let from = '';
let body = '';
let receivedAt = new Date().toISOString();
let messageId = '';

if (looksLikeGmail) {
  triggerType = 'gmail';
  source = 'gmail';
  subject = asText(item.subject || item.Subject);
  from = asText(item.from || item.From || (item.headers && item.headers.from));
  body = asText(item.text || item.snippet || item.textPlain || item.textHtml || item.html || '');
  receivedAt = item.internalDate ? new Date(Number(item.internalDate)).toISOString() : receivedAt;
  messageId = asText(item.id || item.messageId);
} else {
  triggerType = 'webhook';
  source = asText(webhookBody.source) || 'webhook';
  subject = asText(webhookBody.subject) || `Lead from ${asText(webhookBody.name) || 'unknown'}`;
  from = asText(webhookBody.email || webhookBody.from);
  const parts = [];
  if (asText(webhookBody.name)) parts.push(`Name: ${asText(webhookBody.name)}`);
  if (asText(webhookBody.email)) parts.push(`Email: ${asText(webhookBody.email)}`);
  if (asText(webhookBody.phone)) parts.push(`Phone: ${asText(webhookBody.phone)}`);
  if (asText(webhookBody.message)) parts.push(`Message: ${asText(webhookBody.message)}`);
  body = parts.join('\n');
  messageId = asText(webhookBody.id || item.id);
}

return {
  triggerType,
  source,
  subject: asText(subject).slice(0, 500),
  from: asText(from).slice(0, 1000),
  body: asText(body).slice(0, 6000),
  receivedAt,
  messageId,
};

