parameters.jsCode:
const src = $('Normalize Input').item.json;
const input = $input.item.json || {};

function stringify(value) {
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  if (Array.isArray(value)) return value.map((entry) => stringify(entry)).filter(Boolean).join(', ');
  if (value && typeof value === 'object') {
    return stringify(value.text || value.value || value.email || value.address || value.name || value.html || '');
  }
  return '';
}

function firstNonEmpty(...values) {
  for (const value of values) {
    const text = stringify(value).trim();
    if (text) return text;
  }
  return '';
}

function lineValue(label, text) {
  const source = stringify(text);
  const match = source.match(new RegExp(`(?:^|\\n)${label}:\\s*(.+)`, 'i'));
  return match ? match[1].trim() : '';
}

function extractEmail(text) {
  const source = stringify(text);
  const match = source.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return match ? match[0] : '';
}

function extractPhone(text) {
  const source = stringify(text);
  const match = source.match(/(?:\+?\d[\d\s().-]{7,}\d)/);
  return match ? match[0].trim() : '';
}

function detectLanguage(text) {
  const sample = stringify(text).trim();
  if (!sample) return '';
  if (/[\u0400-\u04FF]/.test(sample)) return 'ru';
  if (/[\u00BF\u00A1\u00F1\u00E1\u00E9\u00ED\u00F3\u00FA]/i.test(sample)) return 'es';
  return 'en';
}

function normalizePriority(value) {
  const raw = stringify(value).trim().toLowerCase();
  if (['high', 'urgent', 'critical'].includes(raw)) return 'high';
  if (['medium', 'med', 'normal'].includes(raw)) return 'medium';
  if (['low', 'minor'].includes(raw)) return 'low';
  return '';
}

function detectServices(text) {
  const lower = stringify(text).toLowerCase();
  const matches = [];
  const map = [
    ['n8n automation', /\bn8n\b|workflow automation|business process automation|lead routing/],
    ['crm integration', /\bcrm\b|hubspot|salesforce|pipedrive/],
    ['ai automation', /\bai\b|llm|chatbot|openai|gemini/],
    ['email automation', /\bgmail\b|email automation|mailbox automation/],
    ['telegram automation', /\btelegram\b|bot/],
    ['web development', /\bwebsite\b|\bweb app\b|landing page/],
    ['custom integration', /integration|api|webhook/],
  ];
  for (const [label, regex] of map) {
    if (regex.test(lower)) matches.push(label);
  }
  return matches;
}

function detectIntent(text) {
  const lower = stringify(text).toLowerCase();
  if (/(unsubscribe|newsletter|mailing list|promo code|discount)/.test(lower)) return 'spam';
  if (/(job application|resume|curriculum vitae|\bcv\b|vacancy|looking for a job|hiring)/.test(lower)) return 'job_application';
  if (/(support|bug|issue|incident|not working|problem|error)/.test(lower)) return 'support';
  if (/(partner|partnership|collaboration|affiliate|reseller)/.test(lower)) return 'partnership';
  if (/(quote|proposal|\brfp\b|estimate|pricing|price|cost|budget)/.test(lower)) return 'request_for_proposal';
  if (/(demo|consultation|strategy call|book a call|meeting)/.test(lower)) return 'consultation';
  if (/(automation|integration|crm|workflow|project|looking for|need help|need an?|want to build|interested in)/.test(lower)) return 'inquiry';
  return 'other';
}

function detectIsLead(sourceText, intent, email, phone, triggerType) {
  const lower = stringify(sourceText).toLowerCase();
  const negative = /(unsubscribe|newsletter|mailing list|receipt|invoice|out of office|auto-reply|automatic reply|do not reply|no-reply)/.test(lower);
  if (negative) return false;
  if (intent === 'spam' || intent === 'job_application') return false;
  const hasContact = !!(stringify(email) || stringify(phone));
  const businessSignal = /(automation|integration|crm|workflow|project|quote|proposal|estimate|pricing|budget|demo|consultation|agency|implementation|development|software)/.test(lower);
  if (triggerType === 'webhook' && hasContact) return true;
  return hasContact && businessSignal;
}

function detectPriority(sourceText, intent, isLead) {
  const lower = stringify(sourceText).toLowerCase();
  if (/(urgent|asap|immediately|today|this week|deadline|high priority)/.test(lower)) return 'high';
  if (intent === 'request_for_proposal') return 'high';
  if (/(budget|\$\d|timeline|proposal|estimate|pricing)/.test(lower)) return 'high';
  if (isLead || /(demo|consultation|meeting|call)/.test(lower)) return 'medium';
  return 'low';
}

function safeJsonParse(text) {
  const source = stringify(text);
  const cleaned = source.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  if (!cleaned) return {};
  try {
    return JSON.parse(cleaned);
  } catch (error) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) return {};
    try {
      return JSON.parse(match[0]);
    } catch (nestedError) {
      return {};
    }
  }
}

let llmRaw = '';
if (Array.isArray(input.candidates) && input.candidates.length > 0) {
  const parts = input.candidates[0].content?.parts;
  if (Array.isArray(parts) && parts.length > 0) llmRaw = parts[0].text || '';
} else if (Array.isArray(input.content) && input.content.length > 0) {
  llmRaw = input.content[0].text || '';
} else if (typeof input.content === 'string') {
  llmRaw = input.content;
} else if (typeof input.body === 'string') {
  llmRaw = input.body;
}

const parsed = typeof llmRaw === 'string' ? safeJsonParse(llmRaw) : (typeof llmRaw === 'object' && llmRaw ? llmRaw : {});
const llmOk = !!Object.keys(parsed || {}).length;
const llmError = firstNonEmpty(
  input.message,
  input.description,
  input.error,
  input.reason
);

const srcSubject = stringify(src.subject);
const srcFrom = stringify(src.from);
const srcBody = stringify(src.body);
const combinedText = [srcSubject, srcFrom, srcBody].filter(Boolean).join('\n');
const webhookName = lineValue('Name', srcBody);
const webhookEmail = lineValue('Email', srcBody);
const webhookPhone = lineValue('Phone', srcBody);
const webhookMessage = lineValue('Message', srcBody);
const subjectLeadMatch = srcSubject.match(/^Lead from\s+(.+)$/i);
const senderEmail = extractEmail(srcFrom);
const bodyEmail = extractEmail(srcBody);
const fallbackEmail = firstNonEmpty(webhookEmail, parsed.email, senderEmail, bodyEmail);
const cleanedFromName = srcFrom.replace(/\s*<[^>]+>\s*/g, '').replace(/"/g, '').trim();
const fallbackName = firstNonEmpty(
  webhookName,
  parsed.name,
  subjectLeadMatch ? subjectLeadMatch[1].trim() : '',
  cleanedFromName && cleanedFromName !== fallbackEmail ? cleanedFromName : ''
);
const fallbackPhone = firstNonEmpty(webhookPhone, parsed.phone, extractPhone(srcBody));
const fallbackCompany = firstNonEmpty(parsed.company, lineValue('Company', srcBody));
const fallbackBudget = firstNonEmpty(parsed.budget, lineValue('Budget', srcBody));
const heuristicIntent = detectIntent(combinedText);
const derivedIsLead = detectIsLead(combinedText, parsed.intent || heuristicIntent, fallbackEmail, fallbackPhone, src.triggerType);
const heuristicPriority = detectPriority(combinedText, parsed.intent || heuristicIntent, derivedIsLead);
const serviceList = Array.isArray(parsed.services) && parsed.services.length > 0 ? parsed.services : detectServices(combinedText);
const normalizedPriority = normalizePriority(parsed.priority);
const bodySummary = firstNonEmpty(webhookMessage, srcBody).replace(/\s+/g, ' ').trim().slice(0, 280);

return {
  received_at: stringify(src.receivedAt),
  trigger_type: stringify(src.triggerType),
  source: stringify(src.source),
  subject: srcSubject,
  raw_from: srcFrom,
  message_id: stringify(src.messageId),
  is_lead: typeof parsed.is_lead === 'boolean' ? parsed.is_lead : derivedIsLead,
  intent: firstNonEmpty(parsed.intent, heuristicIntent, 'other'),
  priority: firstNonEmpty(normalizedPriority, heuristicPriority, 'low'),
  name: fallbackName,
  email: fallbackEmail,
  phone: fallbackPhone,
  company: fallbackCompany,
  budget: fallbackBudget,
  services: Array.isArray(serviceList) ? serviceList.join(', ') : stringify(serviceList),
  summary: firstNonEmpty(parsed.summary, bodySummary),
  language: firstNonEmpty(parsed.language, detectLanguage(combinedText)),
  confidence: typeof parsed.confidence === 'number' ? parsed.confidence : (llmOk ? 0.7 : (derivedIsLead ? 0.45 : 0.25)),
  classification_mode: llmOk ? 'llm' : 'heuristic_fallback',
  llm_error: llmOk ? '' : llmError,
  message: firstNonEmpty(webhookMessage, srcBody).slice(0, 4000),
  body_preview: srcBody.slice(0, 500),
};

